# index.html
`html
<!DOCTYPE html>
<html lang="zh-CN">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>奇幻选择之旅</title>
<link rel="stylesheet" href="style.css">
</head>
<body>
<div id="app">
<!- 标题区 ->
<header>
<h1>🏰 奇幻选择之旅</h1>
<div id="progress-container">
<div id="progress-label">进度</div>
<div id="progress-bar"><div id="progress-fill"></div></div>
<div id="chapter-tag">序章</div>
</div>
</header>
<!- 配图区（Canvas像素画） ->
<canvas id="scene-canvas" width="400" height="200"></canvas>
<!- 故事区 ->
<div id="story-area">
<p id="story-text">加载中.</p>
</div>
<!- 选项区 ->
<div id="options-area"></div>
<!- 状态区 ->
<div id="status-area">
<span id="ending-count">已发现结局：0 / 2</span>
<button id="restart-btn" style="display:none;">🔄 重新开始</button>
</div>
<script src="story_data.js"></script>
<script src="story_engine.js"></script>
</body>
</html>
`
