# story_engine.js
`javascript
// 奇幻选择之旅 —— 故事引擎
// - 状态 -
let currentChapterId = "start";
let discoveredEndings = new Set();
let totalEndings = STORY_DATA.endings.length;
let history = [];
// - DOM 引用 -
const storyText = document.getElementById("story-text");
const optionsArea = document.getElementById("options-area");
const progressFill = document.getElementById("progress-fill");
const chapterTag = document.getElementById("chapter-tag");
const endingCount = document.getElementById("ending-count");
const restartBtn = document.getElementById("restart-btn");
const canvas = document.getElementById("scene-canvas");
const ctx = canvas.getContext("2d");
// - 像素画绘制 -
function drawScene(sceneId) {
ctx.clearRect(0, 0, 400, 200);
ctx.imageSmoothingEnabled = false;
if (sceneId === "forest") {
// 迷雾森林
ctx.fillStyle = "#1a2b1f"; ctx.fillRect(0, 0, 400, 200);
for (let i = 0; i < 12; i++) {
ctx.fillStyle = "#2d4a2d";
ctx.fillRect(20 + i * 32, 80, 20, 100);
ctx.fillStyle = "#3a5c3a";
ctx.fillRect(10 + i * 32, 60, 8, 8);
}
ctx.fillStyle = "#c8d8b5"; ctx.globalAlpha = 0.25;
for (let i = 0; i < 20; i++) {
ctx.fillRect(Math.random() * 400, Math.random() * 200, 8, 8);
}
ctx.globalAlpha = 1;
} else if (sceneId === "cabin") {
ctx.fillStyle = "#2d1b0e"; ctx.fillRect(0, 0, 400, 200);
ctx.fillStyle = "#5c3a1e"; ctx.fillRect(120, 60, 160, 120);
ctx.fillStyle = "#8b6914"; ctx.fillRect(160, 100, 40, 50);
ctx.fillStyle = "#f5deb3"; ctx.fillRect(140, 70, 20, 20);
ctx.fillStyle = "#3a2a1a";
for (let i = 0; i < 8; i++) ctx.fillRect(128 + i * 18, 56, 6, 8);
} else if (sceneId === "lake") {
ctx.fillStyle = "#1a2b3a"; ctx.fillRect(0, 0, 400, 200);
ctx.fillStyle = "#2a5a7a"; ctx.fillRect(40, 80, 320, 100);
ctx.fillStyle = "#f5e6c8"; ctx.beginPath(); ctx.arc(320, 60, 30, 0, Math.PI * 2); ctx.fill();
for (let i = 0; i < 10; i++) {
ctx.fillStyle = "rgba(255,255,200,0.15)";
ctx.fillRect(60 + i * 30, 90 + (i % 3) * 20, 10, 4);
}
} else if (sceneId === "forge") {
ctx.fillStyle = "#2a1a0a"; ctx.fillRect(0, 0, 400, 200);
ctx.fillStyle = "#6b3a1a"; ctx.fillRect(160, 140, 80, 40);
ctx.fillStyle = "#ff6a00";
for (let i = 0; i < 5; i++) ctx.fillRect(175 + i * 10, 145, 6, 6);
ctx.fillStyle = "#4a2a1a"; ctx.fillRect(100, 40, 40, 80);
} else if (sceneId === "garden") {
ctx.fillStyle = "#1a2a1a"; ctx.fillRect(0, 0, 400, 200);
for (let i = 0; i < 6; i++) {
const colors = ["#ff6b8a", "#ffd700", "#7bf5a0", "#b0a0ff", "#ff8c42", "#ff4d6d"];
ctx.fillStyle = colors[i % colors.length];
ctx.fillRect(40 + i * 55, 100 + (i % 2) * 30, 20, 20);
}
ctx.fillStyle = "#5a8ab5"; ctx.fillRect(180, 80, 40, 60);
for (let i = 0; i < 8; i++) {
ctx.fillStyle = "rgba(255,255,200,0.25)";
ctx.fillRect(20 + i * 50, 90 + (i % 2) * 20, 6, 6);
}
} else if (sceneId === "good") {
ctx.fillStyle = "#0a1a2a"; ctx.fillRect(0, 0, 400, 200);
ctx.fillStyle = "#ffd700";
for (let i = 0; i < 15; i++) {
ctx.fillRect(20 + i * 26, 80 + (i % 3) * 30, 10, 10);
}
ctx.fillStyle = "#f0e6d2";
ctx.font = "14px monospace";
ctx.fillText("✨", 180, 100);
} else if (sceneId === "bad") {
ctx.fillStyle = "#2a2a2a"; ctx.fillRect(0, 0, 400, 200);
ctx.fillStyle = "#5a5a5a"; ctx.fillRect(140, 100, 120, 80);
ctx.fillStyle = "#8a8a7a";
for (let i = 0; i < 6; i++) ctx.fillRect(160 + i * 16, 110, 8, 8);
ctx.fillStyle = "#c8c8b0";
ctx.font = "12px monospace";
ctx.fillText("🌅", 180, 140);
}
// - 显示章节 -
function showChapter(chapterId) {
currentChapterId = chapterId;
history.push(chapterId);
// 查找章节
let chapter = STORY_DATA.chapters.find(c => c.id === chapterId);
if (!chapter) {
// 可能是结局
showEnding(chapterId);
return;
}
// 更新 UI
storyText.textContent = chapter.text;
chapterTag.textContent = chapter.title;
drawScene(chapter.image || "forest");
// 更新进度条
const totalSteps = STORY_DATA.chapters.length;
const currentIndex = STORY_DATA.chapters.findIndex(c => c.id === chapterId);
const progress = Math.min(((currentIndex + 1) / totalSteps) * 100, 100);
progressFill.style.width = progress + "%";
// 清空选项并生成新选项
optionsArea.innerHTML = "";
chapter.options.forEach(opt => {
const btn = document.createElement("button");
btn.className = "option-btn";
btn.textContent = opt.text;
btn.addEventListener("click", () => {
showChapter(opt.next);
});
optionsArea.appendChild(btn);
});
restartBtn.style.display = "none";
}
// - 显示结局 -
function showEnding(endingId) {
let ending = STORY_DATA.endings.find(e => e.id === endingId);
if (!ending) return;
storyText.textContent = ending.text;
chapterTag.textContent = ending.title;
drawScene(ending.image || "bad");
progressFill.style.width = "100%";
// 记录结局
discoveredEndings.add(endingId);
endingCount.textContent = `已发现结局：${discoveredEndings.size} / ${totalEndings}`;
// 选项区显示结局提示
optionsArea.innerHTML = "";
const msg = document.createElement("p");
msg.textContent = "🏁 你已到达故事终点";
msg.style.color = "#f5deb3";
msg.style.fontSize = "18px";
msg.style.textAlign = "center";
msg.style.padding = "12px";
optionsArea.appendChild(msg);
// 显示重新开始按钮
restartBtn.style.display = "inline-block";
}
// - 重新开始 -
function restartGame() {
history = [];
showChapter("start");
restartBtn.style.display = "none";
}
// - 初始化 -
restartBtn.addEventListener("click", restartGame);
showChapter("start");
`
