ctx.fillStyle = "rgba(255, 255, 200, 0.3)";
for (let i = 0; i < 5; i++) {
ctx.fillRect(20 + i * 80, 50 + (i % 2) * 30, 6, 6);
}
break;
case "good":
ctx.fillStyle = "#0a1a2a";
ctx.fillRect(0, 0, 400, 200);
ctx.fillStyle = "#ffd700";
for (let i = 0; i < 10; i++) {
ctx.beginPath();
ctx.arc(30 + i * 38, 50 + (i % 3) * 40, 8, 0, Math.PI * 2);
ctx.fill();
