/* =============================================
奇幻选择之旅 — 叙事引擎 (正式完整版)
负责页面渲染、交互、结局判断
============================================= */
(function() {
'use strict';
// - DOM 引用 -
const iconEl = document.getElementById('scene-icon');
const titleEl = document.getElementById('scene-title');
const textEl = document.getElementById('scene-text');
const choicesEl = document.getElementById('choices-container');
const endingLabel = document.getElementById('ending-label');
const restartBtn = document.getElementById('restart-btn');
// - 状态 -
let currentNodeId = 'start';
let currentNode = null;
// - 核心渲染 -
function renderNode(nodeId) {
// 保护性检查
if (!storyData || !storyData[nodeId]) {
console.error('故事节点不存在:', nodeId);
nodeId = 'start';
}
currentNodeId = nodeId;
currentNode = storyData[nodeId];
// 图标
iconEl.textContent = getSceneImage(currentNode.scene);
// 标题
titleEl.textContent = currentNode.title;
// 正文
textEl.textContent = currentNode.text;
// 选项
choicesEl.innerHTML = '';
if (currentNode.choices && currentNode.choices.length > 0) {
currentNode.choices.forEach(function(choice) {
const btn = document.createElement('button');
btn.className = 'choice-btn';
btn.textContent = choice.text;
btn.addEventListener('click', function() {
renderNode(choice.next);
});
choicesEl.appendChild(btn);
});
}
// 结局标签与重新开始
if (currentNode.isEnding) {
let label = '';
switch (currentNode.endingType) {
case 'good': label = '★ 好结局'; break;
case 'bad': label = '★ 坏结局'; break;
case 'hidden': label = '★ 隐藏结局'; break;
default: label = '☆ 普通结局'; break;
}
endingLabel.textContent = label;
restartBtn.style.display = 'inline-block';
} else {
endingLabel.textContent = '';
restartBtn.style.display = 'none';
}
// 滚动到顶部
window.scrollTo({ top: 0, behavior: 'smooth' });
}
// - 重新开始 -
restartBtn.addEventListener('click', function() {
renderNode('start');
});
// - 安全启动 -
// 确保 DOM 完全加载后再执行
if (document.readyState === 'loading') {
document.addEventListener('DOMContentLoaded', function() {
renderNode('start');
});
} else {
renderNode('start');
}
})();
