// 奇幻选择之旅 — 叙事引擎
(function() {
'use strict';
var iconEl = document.getElementById('scene-icon');
var titleEl = document.getElementById('scene-title');
var textEl = document.getElementById('scene-text');
var choicesEl = document.getElementById('choices-container');
var endingLabel = document.getElementById('ending-label');
var restartBtn = document.getElementById('restart-btn');
function renderNode(nodeId) {
if (!window.storyData || !window.storyData[nodeId]) {
console.error('节点不存在，回退到 start');
nodeId = 'start';
}
var node = window.storyData[nodeId];
iconEl.textContent = getSceneImage(node.scene);
titleEl.textContent = node.title;
textEl.textContent = node.text;
choicesEl.innerHTML = '';
if (node.choices && node.choices.length > 0) {
node.choices.forEach(function(choice) {
var btn = document.createElement('button');
btn.className = 'choice-btn';
btn.textContent = choice.text;
btn.addEventListener('click', function() {
renderNode(choice.next);
});
choicesEl.appendChild(btn);
});
}
if (node.isEnding) {
var labelText = '';
switch (node.endingType) {
case 'good': labelText = '★ 好结局'; break;
case 'bad': labelText = '★ 坏结局'; break;
case 'hidden': labelText = '★ 隐藏结局'; break;
default: labelText = '☆ 普通结局'; break;
}
endingLabel.textContent = labelText;
restartBtn.style.display = 'inline-block';
} else {
endingLabel.textContent = '';
restartBtn.style.display = 'none';
}
window.scrollTo({ top: 0, behavior: 'smooth' });
}
restartBtn.addEventListener('click', function() {
renderNode('start');
});
// 页面加载完毕后立即渲染
if (document.readyState === 'loading') {
document.addEventListener('DOMContentLoaded', function() {
renderNode('start');
});
} else {
renderNode('start');
}
})();
