}
/* ===== 选项 ===== */
#choices-container {
display: flex;
flex-direction: column;
gap: 12px;
margin-bottom: 16px;
}
.choice-btn {
background: linear-gradient(135deg, #2a1f5e, #1e1648);
border: 1px solid #4e3a8a;
border-radius: 14px;
padding: 16px 22px;
font-size: 17px;
color: #dccfff;
cursor: pointer;
transition: all 0.25s ease;
text-align: left;
font-weight: 500;
letter-spacing: 0.5px;
box-shadow: 0 2px 6px rgba(0,0,0,0.3);
}
.choice-btn:hover {
background: linear-gradient(135deg, #392a70, #261e58);
border-color: #785acf;
box-shadow: 0 0 20px rgba(120, 90, 207, 0.35);
transform: translateY(-2px);
}
.choice-btn:active {
transform: translateY(0);
box-shadow: 0 0 10px rgba(120, 90, 207, 0.2);
}
/* ===== 底部 ===== */
#footer-info {
margin-top: 12px;
display: flex;
justify-content: center;
align-items: center;
gap: 16px;
flex-wrap: wrap;
}
#ending-label {
font-size: 16px;
color: #9a8fc0;
font-style: italic;
font-weight: 500;
}
#restart-btn {
background: #3a2f6a;
border: 1px solid #5e4a9a;
color: #e0d8f0;
padding: 10px 28px;
border-radius: 40px;
font-size: 16px;
