}
#restart-btn:hover {
background: #4e3a8a;
box-shadow: 0 0 14px rgba(120, 90, 207, 0.4);
}
/* ===== 统计 ===== */
#stats {
margin-top: 16px;
text-align: center;
font-size: 14px;
color: #7a6fa0;
}
#ending-count {
color: #b8a8e0;
font-weight: 700;
}
/* ===== 响应式 ===== */
@media (max-width: 480px) {
#app {
padding: 20px 14px;
}
#scene-icon {
font-size: 48px;
}
#scene-title {
font-size: 20px;
}
#scene-text {
font-size: 15px;
}
.choice-btn {
font-size: 15px;
padding: 14px 16px;
}
