const sceneTitle = document.getElementById('scene-title');
const sceneText = document.getElementById('scene-text');
const choicesDiv = document.getElementById('choices');
const progressStage = document.getElementById('progress-stage');
const endingLabel = document.getElementById('ending-label');
const restartBtn = document.getElementById('restart-btn');
const endingCountSpan = document.getElementById('ending-count');
let discoveredEndings = new Set();
let currentNodeId = 'start';
function renderNode(nodeId) {
const node = storyData[nodeId];
if (!node) { console.error('节点不存在:', nodeId); return; }
currentNodeId = nodeId;
sceneIcon.textContent = getSceneImage(node.scene);
sceneTitle.textContent = node.title;
sceneText.textContent = node.text;
// 进度
if (node.id.startsWith('start') || node.id.startsWith('forest_path')||node.id.startsWith('waterfall')||node.id.startsWith('tree_top')) progressStage.textContent = '序章';
else if (node.id.startsWith('sword_path')||node.id.startsWith('crystal_path')||node.id.startsWith('cautious_path')||node.id.startsWith('old_man')||node.id.startsWith('underwater')||node.id.startsWith('mountain_path')||node.id.startsWith('ruins')) progressStage.textContent = '第一章';
else if (node.id.startsWith('library')||node.id.startsWith('gold_tower')||node.id.startsWith('warrior_path')||node.id.startsWith('mage_path')||node.id.startsWith('assin_path')||node.id.startsWith('ancient_temple')||node.id.startsWith('drum_ritual')||node.id.startsWith('deep_forest')||node.id.startsWith('world_tree')||node.id.startsWith('old_man_truth')||node.id.startsWith('water_gate')||node.id.startsWith('waterfall_return')||node.id.startsWith('water_crystal')||node.id.startsWith('heal_self')||node.id.startsWith('darkness')) progressStage.textContent = '第二章';
else if (node.id.startsWith('seal_fissure')||node.id.startsWith('research_more')||node.id.startsWith('find_ally')) progressStage.textContent = '第三章';
else progressStage.textContent = '终章';
// 清除选项
choicesDiv.innerHTML = '';
if (node.choices && node.choices.length > 0) {
node.choices.forEach(function(choice) {
const btn = document.createElement('button');
btn.className = 'choice-btn';
btn.textContent = choice.text;
btn.addEventListener('click', function() { renderNode(choice.next); });
choicesDiv.appendChild(btn);
});
}
// 结局
if (node.isEnding) {
let labelText = '';
switch (node.endingType) {
case 'good': labelText = '★ 好结局'; break;
case 'bad': labelText = '★ 坏结局'; break;
case 'hidden': labelText = '★ 隐藏结局'; break;
default: labelText = '☆ 普通结局'; break;
}
endingLabel.textContent = labelText;
restartBtn.style.display = 'inline-block';
discoveredEndings.add(nodeId);
endingCountSpan.textContent = discoveredEndings.size + ' / 5';
} else {
endingLabel.textContent = '';
restartBtn.style.display = 'none';
}
window.scrollTo({ top: 0, behavior: 'smooth' });
}
restartBtn.addEventListener('click', function() {
renderNode('start');
});
// 启动
renderNode('start');
