function getSceneImage(sceneId) {
var map = {
"forest_night":"🌙","forest_path":"🌲","waterfall":"💧",
"tree_top":"🌳","stone_circle":"🗿","crystal_glow":"💎",
"ancient_road":"🛤️","old_man":"🧙","underwater":"🌊",
"library":"📚","rainbow":"🌈","ending_good":"✨",
"golden_road":"🛣️","darkness":"🌑","ending_dark":"🖤",
"seal":"🔒","hidden_temple":"🏛️","gold_tower":"🏰",
"ruins":"🏛️","mountain_pass":"⛰️","warrior_trial":"⚔️",
"mage_trial":"🔮","assin_trial":"🗡️","temple":"🏛️",
"ritual":"🥁","deep_forest":"🌲","world_tree":"🌍",
"truth":"⭐","ending_normal":"🌅","water_crystal":"💠",
"library_deep":"📖","alliance":"🤝","ending_escape":"🏃","water_gate":"🚪"
};
return map[sceneId] || "🌌";
}
// ===================== 引擎 =====================
(function() {
var iconEl = document.getElementById('scene-icon');
var titleEl = document.getElementById('scene-title');
var textEl = document.getElementById('scene-text');
var choicesEl = document.getElementById('choices-container');
var endingLabel = document.getElementById('ending-label');
var restartBtn = document.getElementById('restart-btn');
var endingCountSpan = document.getElementById('ending-count');
var discoveredEndings = new Set();
var totalEndings = 5;
function renderNode(nodeId) {
var node = storyData[nodeId];
if (!node) {
console.error('节点不存在:', nodeId);
return;
}
iconEl.textContent = getSceneImage(node.scene);
titleEl.textContent = node.title;
textEl.textContent = node.text;
choicesEl.innerHTML = '';
if (node.choices && node.choices.length > 0) {
for (var i = 0; i < node.choices.length; i++) {
var choice = node.choices[i];
var btn = document.createElement('button');
btn.className = 'choice-btn';
btn.textContent = choice.text;
btn.addEventListener('click', (function(next) {
return function() { renderNode(next); };
})(choice.next));
choicesEl.appendChild(btn);
}
if (node.isEnding) {
var labelText = '';
switch (node.endingType) {
case 'good': labelText = '★ 好结局'; break;
case 'bad': labelText = '★ 坏结局'; break;
case 'hidden': labelText = '★ 隐藏结局'; break;
default: labelText = '☆ 普通结局'; break;
}
endingLabel.textContent = labelText;
restartBtn.style.display = 'inline-block';
discoveredEndings.add(nodeId);
endingCountSpan.textContent = discoveredEndings.size + ' / 5';
} else {
endingLabel.textContent = '';
restartBtn.style.display = 'none';
}
window.scrollTo({ top: 0, behavior: 'smooth' });
}
restartBtn.addEventListener('click', function() {
renderNode('start');
});
// 启动
renderNode('start');
})();
</script>
</body>
</html>
