function render(id) {
var node = storyData[id];
if (!node) { id = 'start'; node = storyData[id]; }
icon.textContent = getSceneImage(node.scene);
title.textContent = node.title;
text.textContent = node.text;
choices.innerHTML = '';
if (node.choices && node.choices.length) {
for (var i = 0; i < node.choices.length; i++) {
var c = node.choices[i];
var btn = document.createElement('button');
btn.className = 'choice-btn';
btn.textContent = c.text;
btn.addEventListener('click', (function(n) { return function() { render(n); }; })(c.next));
choices.appendChild(btn);
}
if (node.isEnding) {
var t = '';
if (node.endingType === 'good') t = '★ 好结局';
else if (node.endingType === 'bad') t = '★ 坏结局';
else if (node.endingType === 'hidden') t = '★ 隐藏结局';
else t = '☆ 普通结局';
endingLabel.textContent = t;
restartBtn.style.display = 'inline-block';
found.add(id);
countSpan.textContent = found.size + ' / 5';
} else {
endingLabel.textContent = '';
restartBtn.style.display = 'none';
}
window.scrollTo({top:0, behavior:'smooth'});
}
restartBtn.addEventListener('click', function() { render('start'); });
render('start');
})();
