<script>
// ===== 故事数据 =====
var storyData = {
"start": { id:"start", title:"序章·觉醒", text:"你从一阵剧烈的头痛中醒来，发现自己躺在一片陌生的森林里。空气中弥漫着古老而神秘的气息，远处的天际被紫色的极光笼罩。\n\n你的记忆一片空白，只隐约记得自己肩负着一项重要的使命。林间小径在月光下泛着微弱的银光，通往三个不同的方向。", scene:"forest_night", choices:[{text:"沿着银光小径走向森林深处", next:"forest_path"},{text:"循着远处的水声前行", next:"waterfall"},{text:"攀上最近的古树观察方向", next:"tree_top"}]},
"forest_path": { id:"forest_path", title:"第一章·银光小径", text:"你沿着银光小径前行，两旁的树木越来越高大，枝叶间闪烁着细碎的荧光。\n\n突然，你注意到路边有一块古老的石碑，上面刻着模糊的文字。石碑旁放着一柄锈蚀的长剑和一枚发蓝光的晶石。", scene:"forest_path", choices:[{text:"拾起长剑，继续前行", next:"sword_path"},{text:"拿起蓝色晶石研究", next:"crystal_path"},{text:"不去触碰任何东西，快步离开", next:"cautious_path"}]},
"waterfall": { id:"waterfall", title:"第一章·月光瀑布", text:"水声越来越近，你拨开最后一片灌木，眼前豁然开朗——一道银色瀑布从百米高的悬崖倾泻而下，汇入下方清澈的深潭。\n\n水面上漂浮着发光的莲花，潭边坐着一位披着斗篷的老者，他似乎在垂钓，但鱼竿上没有鱼线。", scene:"waterfall", choices:[{text:"上前与老者交谈", next:"old_man"},{text:"潜入深潭探索水下", next:"underwater"},{text:"绕行瀑布，寻找上山的路", next:"mountain_path"}]},
"tree_top": { id:"tree_top", title:"第一章·古树之巅", text:"你费尽全力攀上那棵参天古树，树冠之上视野极为开阔。你看到这片森林被一圈山脉环绕，宛如一个巨大的碗。\n\n远处有三座高塔发出微弱的光芒：一座金色、一座银色、一座黑色。森林中央有一片开阔的废墟，似乎是一座远古城市的遗迹。", scene:"tree_top", choices:[{text:"朝金色高塔方向前进", next:"gold_tower"},{text:"前往中央废墟探索", next:"ruins"},{text:"仔细观察山脉，寻找出口", next:"mountain_pass"}]},
"sword_path": { id:"sword_path", title:"第二章·试炼之剑", text:"你提着锈蚀的长剑继续前进，手中的武器虽然古老，却意外地轻盈。小径逐渐开阔，前方出现一片被石柱环绕的圆形广场。\n\n广场中央站着三个石像——战士、法师、刺客——每个石像脚下都有一行发光的铭文。", scene:"stone_circle", choices:[{text:"在战士石像前跪下，宣誓守护", next:"warrior_path"},{text:"触摸法师石像手中的水晶球", next:"mage_path"},{text:"检查刺客石像背后的暗门", next:"assin_path"}]},
"crystal_path": { id:"crystal_path", title:"第二章·幽蓝晶石", text:"蓝色晶石一接触到你的手指，立刻发出柔和的光芒，一股温暖的力量流遍全身。\n\n你看到晶石内部浮现出指引方向的幻影——一座隐藏在山壁后的图书馆。同时，你也感到一股黑暗的气息正在森林某处苏醒。", scene:"crystal_glow", choices:[{text:"跟随晶石的指引前往图书馆", next:"library"},{text:"循着黑暗气息的方向去探查", next:"darkness"},{text:"尝试用晶石的力量治疗自己", next:"heal_self"}]},
"cautious_path": { id:"cautious_path", title:"第二章·谨慎前行", text:"你快步离开石碑，心中隐约感到不安。走出一段距离后，你发现地上有一些古老的石板，似乎是一条被遗忘的道路。\n\n石板上的符号在月光下隐发光，组成了一条曲折的路径。远处传来低沉的鼓声，节奏缓慢而庄严。", scene:"ancient_road", choices:[{text:"沿着石板路前进", next:"ancient_temple"},{text:"潜伏着向鼓声方向摸去", next:"drum_ritual"},{text:"偏离道路进入密林躲藏", next:"deep_forest"}]},
"old_man": { id:"old_man", title:"第二章·垂钓者", text:"老者缓转过头来，他的眼睛深邃如星空，仿佛能看穿你的灵魂。\n\n\"你终于来了，\"他说，声音如同风吹过古老的石壁，\"我等你很久了。这个世界正在失去它的色彩，而你是唯一能修复它的人。\"\n\n他递给你一枚古旧的铜币，上面刻着一棵世界树的图案。", scene:"old_man", choices:[{text:"接受铜币，询问自己的使命", next:"world_tree"},{text:"质疑老者，询问他的身份", next:"old_man_truth"},{text:"拒绝铜币，自己寻找答案", next:"refuse_quest"}]},
"underwater": { id:"underwater", title:"第二章·水底秘境", text:"你深吸一口气潜入潭中，水下的世界远比想象中瑰丽。发光的鱼群在石柱间穿梭，水底有一道隐约可见的拱门。\n\n拱门上的铭文还在发光，似乎是一道传送门。但你的氧气不多了——你必须做出选择。", scene:"underwater", choices:[{text:"游向拱门，穿过传送门", next:"water_gate"},{text:"浮上水面换气再决定", next:"waterfall_return"},{text:"收集一些发光的水晶再走", next:"water_crystal"}]},
"mountain_path": { id:"mountain_path", title:"第二章·山隘", text:"你在山顶发现了一条狭窄的山隘，风从隘口吹来，带来远方的气息。隘口处有一座古老的哨塔，里面可能有人居住。", scene:"mountain_pass", choices:[{text:"进入哨塔", next:"old_man"},{text:"直接穿过隘口", next:"gold_tower"}]},
"library": { id:"library", title:"第三章·幽蓝图书馆", text:"晶石引导你找到了一座隐藏在山壁中的古老图书馆。高耸的书架直达穹顶，无数古籍在魔法光芒中静悬浮。\n\n在图书馆中央，一本摊开的书页上写着世界的真相：这个世界的色彩被一位暗影君王盗取，封印在三座高塔之中。只要找回三种原色——勇气之金、智慧之银、牺牲之黑——世界就能恢复。", scene:"library", choices:[{text:"接受使命，踏上收集三原色之路", next:"quest_accept"},{text:"先查阅更多的古籍寻找线索", next:"research_more"},{text:"带着书籍离开，寻找盟友", next:"find_ally"}]},
"gold_tower": { id:"gold_tower", title:"第三章·金色高塔", text:"你朝着金色高塔的方向穿行，森林逐渐变成金色的丘陵。空气中弥漫着阳光和蜂蜜的味道。\n\n一座宏伟的金色高塔矗立在山丘之巅，塔顶的光辉如同第二个太阳。塔门敞开，似乎欢迎你的到来。", scene:"gold_tower", choices:[{text:"进入金色高塔", next:"quest_accept"},{text:"先在高塔四周探查", next:"quest_accept"}]},
"ruins": { id:"ruins", title:"第二章·远古废墟", text:"你来到森林中央的废墟，破碎的石柱上爬满发光的藤蔓。地面上镶嵌着一幅巨大的星图，中央的凹槽看起来正好能放下一枚铜币。", scene:"ruins", choices:[{text:"将铜币放入凹槽", next:"quest_accept"},{text:"仔细研究星图", next:"quest_accept"}]},
"warrior_path": { id:"warrior_path", title:"第三章·勇者之路", text:"你在战士石像前单膝跪下，地面开始震动。石像的眼睛亮起金光，一柄真正的符文之剑从石像手中脱落，插在你面前的地面上。\n\n\"勇气的考验你已经通过，\"一个声音回荡在广场上，\"带着这把剑，去取回属于这个世界的金色之光。\"", scene:"warrior_trial", choices:[{text:"拔出符文之剑", next:"quest_accept"},{text:"谢绝剑，选择用自己的方式", next:"library"}]},
"mage_path": { id:"mage_path", title:"第三章·智者之路", text:"当你触摸水晶球时，强烈的光芒笼罩了你。你看到了这个世界的过去——远古的战争、色彩的失落、三座高塔的建立。\n\n水晶球赋予你解读一切古代文字的能力。", scene:"mage_trial", choices:[{text:"前往图书馆解读书籍", next:"library"},{text:"用新获得的能力寻找盟友", next:"find_ally"}]},
"assin_path": { id:"assin_path", title:"第三章·影者之路", text:"你打开暗门，发现一条通向下方的密道。密道中保存着各种精巧的工具和一张地图，地图上标注了所有黑暗裂缝的位置。", scene:"assin_trial", choices:[{text:"按照地图前往封印裂缝", next:"seal_fissure"},{text:"带上工具前往金色高塔", next:"gold_tower"}]},
"ancient_temple": { id:"ancient_temple", title:"第三章·远古神庙", text:"石板路将你带到一座半沉入地下的神庙。神庙的大门上刻着铭文：\"唯有理解牺牲之人，方能进入。\"\n\n门前有一个天平的浮雕，一边放着羽毛，另一边空着。", scene:"temple", choices:[{text:"割下一缕头发放在天平上", next:"quest_accept"},{text:"滴一滴血在空着的一边", next:"quest_accept"}]},
"drum_ritual": { id:"drum_ritual", title:"第三章·鼓之仪式", text:"你悄靠近鼓声来源，发现是一群穿着兽皮的林精在举行仪式。他们围绕着篝火击鼓跳舞，中央供奉着一颗发光的金色果实。", scene:"ritual", choices:[{text:"走上前去加入仪式", next:"find_ally"},{text:"趁乱偷走金色果实", next:"quest_accept"}]},
"deep_forest": { id:"deep_forest", title:"第三章·密林迷踪", text:"你躲进密林，走着发现自己迷路了。树木越来越密，天色越来越暗。\n\n就在你几乎绝望时，一只发光的蝴蝶飞来，在你面前盘旋，似乎想为你引路。", scene:"deep_forest", choices:[{text:"跟随发光的蝴蝶", next:"library"},{text:"自己凭直觉走", next:"darkness"}]},
"world_tree": { id:"world_tree", title:"第三章·世界树", text:"铜币在你手中发热，幻象显现——一棵无限延伸的巨大世界树，每一片树叶就是一个世界。你看到这个世界的树叶正在枯黄，而你的使命是将色彩重新注入。", scene:"world_tree", choices:[{text:"立刻前往东方金色塔", next:"gold_tower"},{text:"先回图书馆收集更多信息", next:"library"},{text:"请求老者与你同行", next:"quest_accept"}]},
"old_man_truth": { id:"old_man_truth", title:"第三章·真相", text:"你直视老者的眼睛，质问他究竟是谁。老者沉默了片刻，然后揭开了斗篷——他并非人类，而是一个由星光凝聚的存在。", scene:"truth", choices:[{text:"相信他，接受使命", next:"world_tree"},{text:"仍然拒绝，自己行动", next:"refuse_quest"}]},
"refuse_quest": { id:"refuse_quest", title:"结局·独行者", text:"你谢绝了老者，也放弃了世界的召唤。你选择独自穿越森林，寻找自己的路。\n\n你最终走出了这片魔法森林，回到了平凡的世界。但你永远无法忘记那片紫色的极光、那座瀑布旁的老者——以及一个无法回答的问题：如果当初我选择了承担，一切会不同？\n\n—— 普通结局：独行者 ——", choices:[], isEnding:true, endingType:"normal"},
"quest_accept": { id:"quest_accept", title:"终章·色彩归来", text:"你举起晶石，宣誓要找回世界的色彩。你的声音在图书馆中回荡，书籍发出共鸣的光芒。\n\n你走出图书馆，天空中的极光开始旋转，三道光芒从三座高塔中射出，在你面前汇聚成一道彩虹之桥。", scene:"rainbow", choices:[{text:"踏上彩虹之桥，继续冒险", next:"good_ending"},{text:"返回瀑布寻找老者告别", next:"farewell_ending"}]},
"good_ending": { id:"good_ending", title:"结局·希望之光", text:"你踏上了彩虹之桥，脚下的光芒温暖而坚定。三座高塔的光芒涌入你的体内，你感到前所未有的力量。\n\n所有失落的色彩重回大地，森林恢复了生机，天空再次湛蓝。你成为了这个世界的守护者，永远守护着色彩与光明。\n\n—— 好结局：希望之光 ——", choices:[], isEnding:true, endingType:"good"},
"farewell_ending": { id:"farewell_ending", title:"结局·启程", text:"你回到瀑布边，老者正在等你。听完你说的一切，他微笑着点头。\n\n\"你做出了正确的选择，\"他说，\"不是每个人都能在得知真相后依然选择承担。去吧，世界在等着你。\"\n\n他手中的无形鱼竿一挥，瀑布水幕分开，露出一条通往远方的金色大道。\n\n—— 好结局：启程 ——", choices:[], isEnding:true, endingType:"good"},
"darkness": { id:"darkness", title:"第三章·黑暗低语", text:"你循着黑暗的气息深入森林，周围的温度越来越低，树木变得扭曲而枯黑。\n\n在一个被黑雾笼罩的空地中，你看到了黑暗的源头——一道裂缝正在吞噬周围的光线。", scene:"darkness", choices:[{text:"抵抗诱惑，封堵裂缝", next:"seal_fissure"},{text:"接受黑暗的力量", next:"dark_ending"},{text:"转身逃离这里", next:"escape_darkness"}]},
"dark_ending": { id:"dark_ending", title:"结局·永夜", text:"当你的手触碰到黑暗的一瞬间，裂缝猛地扩张，无穷的黑暗将你吞没。\n\n你成为了暗影君王的一部分，永远徘徊在这片被诅咒的森林中，等待着下一个迷途的灵魂。\n\n—— 坏结局：永夜 ——", choices:[], isEnding:true, endingType:"bad"},
"seal_fissure": { id:"seal_fissure", title:"第四章·封印", text:"你集中意志力，举起蓝色晶石，让它的光芒对抗黑暗。两股力量在空中激烈碰撞，周围的树木在能量的冲击下化为齑粉。\n\n就在你快要支撑不住时，晶石迸发出最后的光芒，将裂缝暂时封堵。", scene:"seal", choices:[{text:"循着神秘声音的方向寻找", next:"secret_ally"},{text:"趁黑暗被封印，前往图书馆", next:"library"}]},
"secret_ally": { id:"secret_ally", title:"结局·隐秘同盟", text:"你跟着神秘声音穿过密林，最终来到一座隐藏的地下神殿。神殿中，三位穿着斗篷的守护者正在等你。\n\n\"你是第一个用光明而非武力封印裂缝的人，\"为首的女性说。她们授予你上古守护者的称号，并将三色结晶交给你。\n\n—— 隐藏结局：隐秘同盟 ——", choices:[], isEnding:true, endingType:"hidden"},
"water_gate": { id:"water_gate", title:"第三章·水门", text:"你穿过传送门，瞬间被水流包裹。当光芒散去，你发现自己躺在图书馆中央的一个水池里——你直接从水下穿越到了图书馆深处。", scene:"library", choices:[{text:"阅读预言书", next:"quest_accept"},{text:"在图书馆中探索更多", next:"research_more"}]},
"waterfall_return": { id:"waterfall_return", title:"第三章·重回瀑布", text:"你浮出水面深吸一口气。老者还在垂钓，他朝你点头：\"水下世界的入口有很多，但需要时机。\"", scene:"waterfall", choices:[{text:"听从老者建议，前往图书馆", next:"library"},{text:"再次尝试潜入水下", next:"underwater"}]},
"water_crystal": { id:"water_crystal", title:"第三章·水之晶石", text:"你收集了几块发光的水晶，它们蕴含着水的记忆。当你触碰其中一块时，你看到了远古守护者将三种原色封入高塔的完整过程。", scene:"water_crystal", choices:[{text:"使用水晶钥匙打开金色高塔", next:"gold_tower"},{text:"前往图书馆解读更多信息", next:"library"}]},
"research_more": { id:"research_more", title:"第四章·无尽知识", text:"你在图书馆中花了不知多久时间研读古籍。你了解到，三原色不仅是颜色的本源，更是世界运转的基石。\n\n你也发现了一个隐藏的记录：除了夺回三原色之外，还有另一种方法——用自己的心成为新的色彩之源。", scene:"library_deep", choices:[{text:"选择成为新的色彩之源", next:"secret_ally"},{text:"按照传统方法前往三座高塔", next:"quest_accept"}]},
"find_ally": { id:"find_ally", title:"第四章·集结盟友", text:"你找到了林精部落和几位独行的守护者。他们听说了你的使命，愿意与你同行。\n\n一支小的队伍集结完成——每个人都有自己的理由守护这个世界。", scene:"alliance", choices:[{text:"带领队伍前往金色高塔", next:"quest_accept"},{text:"先封印附近的黑暗裂缝", next:"seal_fissure"}]},
"escape_darkness": { id:"escape_darkness", title:"结局·逃离", text:"你拼命逃离黑暗之地，裂缝低语的声音在你脑中回响了很久才逐渐消散。\n\n你回到森林边缘，精疲力竭地倒下。虽然你活了下来，但你知道黑暗正在扩张——而你选择了逃，而不是战。\n\n—— 普通结局：逃离 ——", choices:[], isEnding:true, endingType:"normal"},
"heal_self": { id:"heal_self", title:"第三章·自愈", text:"你集中精神，引导晶石的能量流向自己的头部。一股清凉的感觉蔓延开来，你的头痛逐渐消失，取而代之的是一段清晰的记忆碎片。\n\n你记起自己来自一个叫\"色彩之城\"的地方——那是在这个世界色彩被夺走之前，你曾经是一个守护者学徒。", scene:"crystal_glow", choices:[{text:"前往色彩之城遗址", next:"quest_accept"},{text:"先利用晶石的力量去图书馆", next:"library"}]}
};
function getSceneImage(sceneId) {
