let currentNode = null;
let history = [];
let chosenLabel = "";
function initStory() {
history = [];
const startNode = STORY.find(s => s.id === "start");
currentNode = startNode;
document.getElementById("storyView").classList.remove("hidden");
document.getElementById("endingView").classList.add("hidden");
renderScene(startNode);
}
function renderScene(node) {
const container = document.getElementById("storyView");
container.classList.remove("fade-in");
void container.offsetWidth;
container.classList.add("fade-in");
document.getElementById("sceneTitle").textContent = node.scene;
document.getElementById("sceneHead").textContent = node.title;
document.getElementById("sceneImage").textContent = node.emoji;
// 进度点
const totalSteps = 3;
const currentStep = node.isEnding ? totalSteps : (history.length + 1 > totalSteps ? totalSteps : history.length + 1);
const bar = document.getElementById("progressBar");
bar.innerHTML = "";
for (let i = 0; i < totalSteps; i++) {
const dot = document.createElement("div");
dot.className = "dot";
if (i < currentStep - 1) dot.classList.add("filled");
else if (i === currentStep - 1 && !node.isEnding) dot.classList.add("active");
bar.appendChild(dot);
}
// 描述文字
const storyText = document.getElementById("storyText");
storyText.textContent = node.desc;
storyText.style.display = "block";
// 选项按钮
const choicesContainer = document.getElementById("choicesContainer");
choicesContainer.innerHTML = "";
const labels = ["A", "B", "C"];
node.choices.forEach((choice, idx) => {
const btn = document.createElement("button");
btn.className = "choice-btn";
btn.innerHTML = `<span class="label">${labels[idx]}</span> ${choice.text}`;
btn.addEventListener("click", () => handleChoice(choice, btn, labels[idx]));
choicesContainer.appendChild(btn);
});
document.getElementById("nextBtn").disabled = true;
chosenLabel = "";
}
function handleChoice(choice, btn, label) {
const allBtns = document.querySelectorAll(".choice-btn");
allBtns.forEach(b => b.disabled = true);
btn.classList.add("chosen");
chosenLabel = label;
const nextNode = STORY.find(s => s.id === choice.next);
if (nextNode) {
history.push(currentNode);
currentNode = nextNode;
document.getElementById("nextBtn").disabled = false;
}
function goNext() {
const node = currentNode;
if (node.isEnding) {
showEnding(node);
} else {
renderScene(node);
}
function showEnding(node) {
document.getElementById("storyView").classList.add("hidden");
document.getElementById("endingView").classList.remove("hidden");
document.getElementById("endingIcon").textContent = node.ending.icon;
document.getElementById("endingTitle").textContent = node.ending.title;
document.getElementById("endingSub").textContent = "✨ 你完成了属于你的奇幻选择之旅 ✨";
document.getElementById("endingStory").textContent = node.ending.story;
}
document.getElementById("nextBtn").addEventListener("click", goNext);
initStory();
</script>
