/* 像素风全局样式 */
* {
margin: 0;
padding: 0;
box-sizing: border-box;
}
body {
background: #2d1b0e;
font-family: 'Courier New', Courier, monospace;
display: flex;
justify-content: center;
align-items: center;
min-height: 100vh;
margin: 0;
padding: 20px;
}
#app {
width: 100%;
max-width: 600px;
background: #3d2b1f;
border: 4px solid #8b7355;
border-radius: 16px;
padding: 24px;
box-shadow: 0 0 0 4px #5c4033;
color: #e8d5b7;
}
/* 标题区 */
header h1 {
text-align: center;
font-size: 28px;
color: #f5deb3;
text-shadow: 2px 2px #3b2a1a;
margin-bottom: 12px;
letter-spacing: 2px;
}
#progress-container {
display: flex;
align-items: center;
gap: 10px;
margin-bottom: 16px;
font-size: 14px;
}
#progress-label {
white-space: nowrap;
color: #c4a97d;
}
#progress-bar {
flex: 1;
height: 12px;
background: #4a3728;
border-radius: 6px;
border: 1px solid #6f5a3e;
overflow: hidden;
}
#progress-fill {
width: 0%;
height: 100%;
background: #8fbc8f;
transition: width 0.5s ease;
border-radius: 6px;
}
#chapter-tag {
background: #5c4033;
padding: 2px 12px;
border-radius: 8px;
font-size: 13px;
white-space: nowrap;
border: 1px solid #8b7355;
}
/* 配图画布 */
#scene-canvas {
display: block;
width: 100%;
height: auto;
aspect-ratio: 400 / 200;
image-rendering: pixelated;
border: 2px solid #8b7355;
border-radius: 8px;
background: #1a2b1f;
margin-bottom: 16px;
}
/* 故事区 */
#story-area {
background: #2a1e14;
border: 2px solid #6f5a3e;
border-radius: 10px;
padding: 16px 20px;
margin-bottom: 16px;
min-height: 80px;
}
#story-text {
font-size: 18px;
line-height: 1.7;
color: #f0e6d2;
text-shadow: 1px 1px #1f140e;
}
/* 选项区 */
#options-area {
display: flex;
flex-direction: column;
gap: 10px;
margin-bottom: 16px;
}
.option-btn {
padding: 12px 16px;
font-size: 16px;
font-family: 'Courier New', Courier, monospace;
background: #5c4033;
color: #f5deb3;
border: 2px solid #8b7355;
border-radius: 8px;
cursor: pointer;
transition: all 0.2s;
text-align: left;
}
.option-btn:hover {
background: #7a5e4a;
border-color: #c4a97d;
transform: translateX(4px);
}
.option-btn:active {
background: #4a3728;
transform: translateX(2px);
}
/* 状态区 */
#status-area {
display: flex;
justify-content: space-between;
align-items: center;
font-size: 14px;
color: #c4a97d;
border-top: 1px solid #6f5a3e;
padding-top: 12px;
margin-top: 4px;
}
#restart-btn {
padding: 6px 16px;
font-size: 14px;
font-family: 'Courier New', Courier, monospace;
background: #4a6b3f;
color: #f5deb3;
border: 2px solid #8b7355;
border-radius: 8px;
cursor: pointer;
transition: 0.2s;
}
